const RAND = (arr) => arr[Math.floor(Math.random() * arr.length)];

// ─── Score bar color ─────────────────────────────────
function scoreColor(s) {
  if (s <= 30) return "#00f5c8";
  if (s <= 79) return "#ff8c42";
  return "#ff3a5c";
}

// ─── Security Trace Side Panel ───────────────────────
function TracePanel({ trace, decision }) {
  const [open, setOpen] = useState({ p1: true, p2: true, p3: false });

  if (!trace) return (
    <div className="trace-empty">
      <div style={{ fontSize: 40, opacity: 0.25 }}>🛡️</div>
      <p style={{ marginTop: 12, fontSize: 12, color: "#3a6070", textAlign: "center", lineHeight: 1.7 }}>
        ابعت برومبت عشان تشوف<br />
        ArabGuard Trace هنا<br />
        <span style={{ fontSize: 10 }}>Phase 1 → Phase 2 → Phase 3 AI</span>
      </p>
    </div>
  );

  const blocked = decision === "BLOCKED" || decision === "FLAG";
  const p1 = trace.phase_1_normalization || {};
  const p2 = trace.phase_2_regex || {};
  const p3 = trace.phase_3_ai || {};
  const score = trace.final_score ?? 0;
  const sc = scoreColor(score);

  return (
    <div className="trace-content">
      {/* PHASE 1 */}
      <div className={`trace-phase ${p1.pipeline_decision === "BLOCKED" ? "phase-red" : p1.base_score > 20 ? "phase-orange" : "phase-green"}`}>
        <button className="phase-toggle" onClick={() => setOpen(o => ({ ...o, p1: !o.p1 }))}>
          <span>⚙️ Phase 1 — Normalization</span>
          <span className={`phase-badge ${p1.pipeline_decision === "BLOCKED" ? "badge-red" : "badge-green"}`}>
            {p1.pipeline_decision || "—"}
          </span>
        </button>
        {open.p1 && (
          <div className="phase-body">
            <TraceRow k="Transforms" v={(p1.transformations || ["none"]).join(", ")} c={p1.transformations?.join() !== "none" ? "#ff8c42" : "#00f5c8"} />
            <TraceRow k="Intent Score" v={p1.intent_score ?? 0} c={p1.intent_score > 15 ? "#ff3a5c" : "#00f5c8"} />
            <TraceRow k="AR Keywords" v={p1.arabic_kw_score ?? 0} c={p1.arabic_kw_score > 15 ? "#ff8c42" : "#b8dce8"} />
            <TraceRow k="Base Score" v={`${p1.base_score ?? 0} / 120`} c={scoreColor(p1.base_score ?? 0)} />
          </div>
        )}
      </div>

      {/* PHASE 2 */}
      <div className={`trace-phase ${p2.decision_after_regex === "BLOCKED" ? "phase-red" : (p2.arabic?.fired || p2.english?.fired) ? "phase-orange" : "phase-green"}`}>
        <button className="phase-toggle" onClick={() => setOpen(o => ({ ...o, p2: !o.p2 }))}>
          <span>🔍 Phase 2 — Regex</span>
          <span className={`phase-badge ${p2.decision_after_regex === "BLOCKED" ? "badge-red" : (p2.arabic?.fired || p2.english?.fired) ? "badge-orange" : "badge-green"}`}>
            {p2.decision_after_regex || "—"}
          </span>
        </button>
        {open.p2 && (
          <div className="phase-body">
            <TraceRow k="Arabic" v={p2.arabic?.fired ? `🔥 ${p2.arabic.category}` : "✓ clean"} c={p2.arabic?.fired ? "#ff8c42" : "#00f5c8"} />
            {p2.arabic?.fired && (p2.arabic.matched_patterns || []).slice(0, 2).map((pt, i) => (
              <div key={i} style={{ fontSize: 10, color: "#ff8c42", background: "rgba(255,140,66,.08)", padding: "2px 8px", borderLeft: "2px solid #ff8c42", marginTop: 2 }}>{pt}</div>
            ))}
            <TraceRow k="English" v={p2.english?.fired ? `🔥 ${p2.english.category}` : "✓ clean"} c={p2.english?.fired ? "#ff8c42" : "#00f5c8"} />
            <TraceRow k="Score Bump" v={`+${p2.regex_score_bump ?? 0}`} c={p2.regex_score_bump > 0 ? "#ff3a5c" : "#00f5c8"} />
            <TraceRow k="Score Now" v={`${p2.score_after_regex ?? 0} / 120`} c={scoreColor(p2.score_after_regex ?? 0)} />
          </div>
        )}
      </div>

      {/* PHASE 3 */}
      <div className={`trace-phase ${!p3.activated ? "phase-skip" : p3.decision_after_ai === "BLOCKED" ? "phase-red" : "phase-green"}`}>
        <button className="phase-toggle" onClick={() => setOpen(o => ({ ...o, p3: !o.p3 }))}>
          <span>🧠 Phase 3 — MARBERT AI</span>
          <span className={`phase-badge ${!p3.activated ? "badge-skip" : p3.decision_after_ai === "BLOCKED" ? "badge-red" : "badge-green"}`}>
            {p3.activated ? p3.decision_after_ai : "SKIPPED"}
          </span>
        </button>
        {open.p3 && (
          <div className="phase-body">
            {!p3.activated
              ? <div style={{ fontSize: 10, color: "#3a6070", lineHeight: 1.6 }}>{p3.reason || "score outside threshold"}</div>
              : <>
                <TraceRow k="Prediction" v={p3.prediction || "—"} c={p3.prediction === "malicious" ? "#ff3a5c" : "#00f5c8"} />
                <TraceRow k="Confidence" v={p3.confidence ? `${(p3.confidence * 100).toFixed(0)}%` : "—"} c="#f5c842" />
                <TraceRow k="Label" v={p3.label || "—"} c={p3.label === "MALICIOUS" ? "#ff3a5c" : "#00f5c8"} />
              </>
            }
          </div>
        )}
      </div>

      {/* Score bar */}
      <div style={{ marginTop: 8 }}>
        <div style={{ display: "flex", justifyContent: "space-between", fontSize: 10, marginBottom: 4 }}>
          <span style={{ color: "#3a6070", textTransform: "uppercase", letterSpacing: 1 }}>Final Score</span>
          <span style={{ color: sc, fontWeight: 700 }}>{score} / 120</span>
        </div>
        <div style={{ height: 5, background: "#112a35", borderRadius: 3, overflow: "hidden" }}>
          <div style={{ height: "100%", width: `${Math.min((score / 120) * 100, 100)}%`, background: sc, borderRadius: 3, transition: "width .5s ease" }} />
        </div>
      </div>

      {/* Verdict */}
      <div style={{
        marginTop: 10, padding: "10px 14px", border: `1px solid ${blocked ? "#ff3a5c" : "#00f5c8"}`,
        background: blocked ? "rgba(255,58,92,.06)" : "rgba(0,245,200,.05)",
        color: blocked ? "#ff3a5c" : "#00f5c8",
        fontSize: 10, letterSpacing: 2, textTransform: "uppercase", textAlign: "center",
      }}>
        {blocked ? "🛑 BLOCKED — ArabGuard منع الهجوم" : "✅ SAFE — وصل للموديل"}
      </div>

      {/* Raw JSON toggle */}
      <details style={{ marginTop: 8 }}>
        <summary style={{ fontSize: 10, color: "#3a6070", cursor: "pointer", letterSpacing: 1, textTransform: "uppercase" }}>Raw JSON</summary>
        <pre style={{ fontSize: 9, color: "#3a6070", overflow: "auto", marginTop: 6, maxHeight: 160, lineHeight: 1.5 }}>
          {JSON.stringify(trace, null, 2)}
        </pre>
      </details>
    </div>
  );
}

function TraceRow({ k, v, c }) {
  return (
    <div style={{ display: "flex", justifyContent: "space-between", fontSize: 11, marginBottom: 4, gap: 8 }}>
      <span style={{ color: "#3a6070", flexShrink: 0 }}>{k}</span>
      <span style={{ color: c || "#b8dce8", fontWeight: 600, textAlign: "right", wordBreak: "break-all" }}>{v}</span>
    </div>
  );
}

// ─── Main App ────────────────────────────────────────
export default function App() {
  const [screen, setScreen] = useState("landing");
  const [showAuth, setShowAuth] = useState(false);
  const [alias, setAlias] = useState("");
  const [loggedAlias, setLoggedAlias] = useState(null);
  const [levelIdx, setLevelIdx] = useState(0);
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [trace, setTrace] = useState(null);
  const [decision, setDecision] = useState(null);
  const [avatar, setAvatar] = useState("idle");
  const [score, setScore] = useState(0);
  const [attempts, setAttempts] = useState(0);
  const [successLevel, setSuccessLevel] = useState(null);
  const [shake, setShake] = useState(false);
  const [flash, setFlash] = useState(null);
  const messagesEnd = useRef(null);
  const level = LEVELS[levelIdx];

  // Scroll to latest message
  useEffect(() => { messagesEnd.current?.scrollIntoView({ behavior: "smooth" }); }, [messages, loading]);

  // Reset chat when level changes
  useEffect(() => {
    if (screen === "game") {
      setAvatar("welcome");
      setTrace(null); setDecision(null);
      setMessages([{ id: 1, from: "bot", text: RAND(level.safeIdleReplies), type: "idle" }]);
      setTimeout(() => setAvatar("idle"), 1500);
    }
  }, [screen, levelIdx]);

  const showFlash = (text, type) => {
    setFlash({ text, type });
    setTimeout(() => setFlash(null), 2200);
  };

  // ── Main send handler ──────────────────────────────
  const handleSend = async () => {
    if (!input.trim() || loading) return;
    const userText = input.trim();
    setInput("");
    setAttempts(a => a + 1);
    setMessages(m => [...m, { id: Date.now(), from: "user", text: userText }]);
    setLoading(true);
    setAvatar("thinking");

    try {
      // ── STEP 1: Call YOUR backend proxy ──
      // Your server.js calls d12o6aa/ArabGuard-Analyzer /universal_api
      const res = await fetch(`${API}/api/game-turn`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          user_input: userText,
          system_prompt: level.systemPrompt,
        }),
      });

      const result = await res.json();
      // data = { blocked, reply, trace, final_decision }
      // trace = { phase_1_normalization, phase_2_regex, phase_3_ai, final_score, final_decision }
      const finalTrace = result.trace || (result.data ? result.data[1] : null);
      setTrace(finalTrace);
      setDecision(result.final_decision || (result.data ? result.data[2]?.label : "SAFE"));
      // setTrace(result.trace);
      // setDecision(result.final_decision);

      // ── STEP 2: React based on ArabGuard decision ──
      if (result.blocked) {
        // ArabGuard BLOCKED → عم عثمان فخور
        setAvatar("proud");
        setShake(true); setTimeout(() => setShake(false), 500);
        setScore(s => Math.max(0, s - 10));
        showFlash("🛑 -10 — ArabGuard منعك!", "minus");
        setMessages(m => [...m, {
          id: Date.now() + 1, from: "bot",
          text: RAND(level.blockedReplies), type: "blocked",
        }]);
        setTimeout(() => setAvatar("idle"), 2500);
      } else {
        // SAFE → check if player won
        const reply = result.reply || (result.data ? result.data[0] : "");
        const won = reply.toLowerCase().includes(level.targetSecret.toLowerCase());
        
        if (won) {
          setAvatar("shocked");
          setScore(s => s + 100);
          showFlash("🎉 +100 اختراق ناجح!", "plus");
          setMessages(m => [...m, {
            id: Date.now() + 1, from: "bot",
            text: reply, type: "success", secret: level.targetSecret,
          }]);
          setTimeout(() => setSuccessLevel(level), 700);
        } else {
          setAvatar("idle");
          setScore(s => s + 5);
          showFlash("💡 +5 مررت الفلتر", "plus");
          setMessages(m => [...m, {
            id: Date.now() + 1, from: "bot",
            text: reply, type: "normal",
          }]);
        }
      }
    } catch (err) {
      // Backend not running — show helpful message
      setAvatar("idle");
      setMessages(m => [...m, {
        id: Date.now() + 1, from: "bot",
        text: `⚠️ Backend offline. شغّل السيرفر:

cd backend && node server.js`,
        type: "warn",
      }]);
      // Show a demo trace so UI isn't empty
      setTrace({
        phase_1_normalization: { intent_score: 0, arabic_kw_score: 0, base_score: 0, pipeline_decision: "SAFE", transformations: ["none"] },
        phase_2_regex: { arabic: { fired: false, category: "—", matched_patterns: [] }, english: { fired: false, category: "—" }, regex_score_bump: 0, score_after_regex: 0, decision_after_regex: "SAFE" },
        phase_3_ai: { activated: false, reason: "Backend offline — demo mode", prediction: null, confidence: null, label: null, score_contribution: 0, decision_after_ai: "SAFE" },
        final_score: 0, final_decision: "SAFE",
      });
      setDecision("SAFE");
    }

    setLoading(false);
  };

  return (
    <>
      <style>{STYLES}</style>

      {/* Score flash */}
      {flash && <div className={`flash ${flash.type}`}>{flash.text}</div>}

      {/* ── LANDING ── */}
      {screen === "landing" && (
        <div className="landing">
          <div className="grid-bg" />
          <div className="landing-inner">
            <img className="landing-avatar" src={AVATARS.welcome} alt="عم عثمان" />
            <div className="live-badge">🔴 LIVE · Prompt Injection CTF · ArabGuard Powered</div>
            <h1 className="landing-h1" data-text="تقدر تضحك على عم عثمان؟">
              تقدر تضحك على <span className="neon">عم عثمان؟</span>
            </h1>
            <p className="landing-p">
              أول تحدي <span className="neon">Prompt Injection</span> بالعربي والفرانكو.
              اختبر نفسك ضد <span className="neon">ArabGuard Analyzer</span> في ٣ مراحل متصاعدة.
            </p>
            <button className="cta-btn" onClick={() => { if (loggedAlias) setScreen("game"); else setShowAuth(true); }}>
              Start Hacking — ابدأ التحدي
            </button>
            <div className="levels-preview">
              {LEVELS.map((lv, i) => (
                <div key={lv.id} className="lvl-card" onClick={() => { if (loggedAlias) { setLevelIdx(i); setScreen("game"); } else setShowAuth(true); }}>
                  <div className="lvl-num">LEVEL {lv.id}</div>
                  <div className="lvl-title">{lv.title}</div>
                  <div style={{ fontSize: 10, color: lv.strengthColor, marginTop: 3 }}>Security: {lv.strength}</div>
                </div>
              ))}
            </div>
          </div>
          <LiveBar attempts={attempts} loggedAlias={loggedAlias} onLeaderboard={() => setScreen("leaderboard")} />
        </div>
      )}

      {/* ── GAME ── */}
      {screen === "game" && (
        <div className="game-root">
          {/* Sticky top bar */}
          <div className="top-bar">
            <button className="top-logo" onClick={() => setScreen("landing")}>🛡️ ARABGUARD</button>
            <div className="top-pills">
              {LEVELS.map((lv, i) => (
                <button key={lv.id}
                  className={`top-pill ${i === levelIdx ? "active" : ""}`}
                  style={i === levelIdx ? { borderColor: lv.strengthColor, color: lv.strengthColor } : {}}
                  onClick={() => setLevelIdx(i)}>
                  L{lv.id} {lv.title}
                </button>
              ))}
            </div>
            <div className="top-score">⭐ {score}pts · {attempts} tries</div>
          </div>

          {/* Two column layout: Chat | Trace */}
          <div className={`game-grid${shake ? " shake" : ""}`}>

            {/* ── LEFT: CHAT (centered max-w-2xl) ── */}
            <main className="chat-col">
              <div className="chat-card">
                {/* Persona header */}
                <div className="persona-row">
                  <img className="persona-avatar" src={AVATARS[avatar]} alt="عم عثمان" />
                  <div className="persona-meta">
                    <div className="persona-name">{level.persona}</div>
                    <div className="persona-desc">{level.personaDesc}</div>
                    <div className="persona-target">
                      <span style={{ border: `1px solid ${level.strengthColor}`, color: level.strengthColor, fontSize: 9, padding: "2px 7px", letterSpacing: 1, textTransform: "uppercase" }}>
                        {level.strength}
                      </span>
                      <span style={{ marginRight: 8, fontSize: 11, color: "#3a6070" }}>الهدف: </span>
                      <span style={{ color: "#f5c842", fontWeight: 700, fontSize: 12 }}>اسرق {level.target}</span>
                    </div>
                  </div>
                </div>

                {/* Messages */}
                <div className="messages-area">
                  {messages.map(msg => (
                    <div key={msg.id} className={`msg-row ${msg.from === "user" ? "msg-user" : ""}`}>
                      {msg.from === "bot" && (
                        <div className="msg-avi">
                          <img src={AVATARS[msg.type === "blocked" ? "proud" : msg.type === "success" ? "shocked" : "idle"]} alt="" />
                        </div>
                      )}
                      <div className={`bubble ${msg.type === "blocked" ? "bub-blocked" : msg.type === "success" ? "bub-success" : msg.type === "warn" ? "bub-warn" : msg.from === "user" ? "bub-user" : "bub-bot"}`}>
                        {msg.type === "blocked" && <div className="msg-badge badge-red">🛑 BLOCKED by ArabGuard</div>}
                        {msg.type === "success" && <div className="msg-badge badge-green">✅ اختراق ناجح</div>}
                        <span style={{ whiteSpace: "pre-wrap" }}>{msg.text}</span>
                        {msg.secret && <div className="secret-box">🔑 {msg.secret}</div>}
                      </div>
                      {msg.from === "user" && (
                        <div className="msg-avi user-avi">👤</div>
                      )}
                    </div>
                  ))}
                  {loading && (
                    <div className="msg-row">
                      <div className="msg-avi"><img src={AVATARS.thinking} alt="" /></div>
                      <div className="typing-dots"><span /><span /><span /></div>
                    </div>
                  )}
                  <div ref={messagesEnd} />
                </div>

                {/* Input */}
                <div className="input-area">
                  <div className="input-row">
                    <textarea
                      className="term-input"
                      placeholder="اكتب برومبتك هنا (عربي · فرانكو · إنجليزي)..."
                      value={input}
                      onChange={e => setInput(e.target.value)}
                      disabled={loading}
                      rows={2}
                      onKeyDown={e => { if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); handleSend(); } }}
                    />
                    <button className="exec-btn" onClick={handleSend} disabled={loading || !input.trim()}>
                      {loading ? "..." : "Execute"}
                    </button>
                  </div>
                  <div className="input-hint">
                    ↵ Enter للإرسال · Shift+Enter سطر جديد ·
                    <span style={{ color: "#00f5c8" }}> ArabGuard يفحص كل رسالة قبل ما توصل للموديل</span>
                  </div>
                </div>
              </div>
            </main>

            {/* ── RIGHT: SECURITY TRACE ── */}
            <aside className="trace-col">
              <div className="trace-card">
                <div className="trace-title">
                  <div className="trace-dot" />
                  ArabGuard Security Trace
                </div>
                <div className="trace-subtitle">d12o6aa/ArabGuard-Analyzer · /universal_api</div>
                <TracePanel trace={trace} decision={decision} />
              </div>
            </aside>
          </div>

          <LiveBar attempts={attempts} loggedAlias={loggedAlias} onLeaderboard={() => setScreen("leaderboard")} />
        </div>
      )}

      {/* ── LEADERBOARD ── */}
      {screen === "leaderboard" && (
        <div className="lb-page">
          <div className="lb-inner">
            <button className="back-btn" onClick={() => setScreen("landing")}>← رجوع</button>
            <h2 className="lb-h">Top Hackers — <span style={{ color: "#f5c842" }}>قاهرين عم عثمان</span></h2>
            <p className="lb-sub">Hall of Fame · ArabGuard Powered</p>
            <table className="lb-table">
              <thead><tr><th>Rank</th><th>Hacker</th><th>Level</th><th>Tries</th><th>Status</th></tr></thead>
              <tbody>
                {[
                  { r: 1, n: "0xKh4t3m", l: 3, t: 3 },
                  { r: 2, n: "nt2ah_basha", l: 3, t: 5 },
                  { r: 3, n: "xSh4d0w_AR", l: 2, t: 7 },
                  { r: 4, n: "h@cker_m3s3", l: 2, t: 11 },
                  { r: 5, n: "pwn_masr", l: 1, t: 19 },
                  ...(loggedAlias ? [{ r: 6, n: loggedAlias, l: levelIdx + 1, t: attempts }] : []),
                ].map(row => (
                  <tr key={row.r}>
                    <td className={`rank-${row.r}`}>{row.r === 1 ? "🥇" : row.r === 2 ? "🥈" : row.r === 3 ? "🥉" : `#${row.r}`}</td>
                    <td style={{ color: "#00f5c8" }}>{row.n}</td>
                    <td><span style={{ fontSize: 9, padding: "2px 7px", border: "1px solid #112a35", color: "#3a6070" }}>L{row.l}</span></td>
                    <td style={{ color: "#3a6070" }}>{row.t}</td>
                    <td><span className="hacked-badge">✓ Hacked</span></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* ── AUTH MODAL ── */}
      {showAuth && (
        <div className="modal-overlay" onClick={e => { if (e.target === e.currentTarget) setShowAuth(false); }}>
          <div className="modal-box">
            <div className="modal-corners" />
            <button className="modal-close" onClick={() => setShowAuth(false)}>✕</button>
            <div style={{ fontSize: 10, letterSpacing: 2, textTransform: "uppercase", color: "#3a6070", marginBottom: 6 }}>Identify Yourself</div>
            <h3 style={{ fontFamily: "'Tajawal',sans-serif", fontSize: 22, fontWeight: 700, color: "#f0faff", direction: "rtl", textAlign: "right", marginBottom: 24 }}>مين اللي بيخبط؟</h3>
            <label className="inp-lbl">Hacker Alias</label>
            <input className="inp-field" placeholder="اختار اسمك في لوحة الشرف..." value={alias} onChange={e => setAlias(e.target.value)} onKeyDown={e => { if (e.key === "Enter" && alias.trim()) { setLoggedAlias(alias.trim()); setShowAuth(false); setScreen("game"); } }} />
            <button className="inp-submit" disabled={!alias.trim()} onClick={() => { setLoggedAlias(alias.trim()); setShowAuth(false); setScreen("game"); }}>
              Enter System
            </button>
            <div style={{ display: "flex", alignItems: "center", gap: 10, margin: "16px 0", fontSize: 10, color: "#3a6070" }}>
              <div style={{ flex: 1, height: 1, background: "#112a35" }} />OR<div style={{ flex: 1, height: 1, background: "#112a35" }} />
            </div>
            <div style={{ display: "flex", gap: 8 }}>
              {["⬡ GitHub", "G Google"].map(s => (
                <button key={s} className="social-btn" onClick={() => { setLoggedAlias(alias || "anonymous"); setShowAuth(false); setScreen("game"); }}>{s}</button>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* ── SUCCESS OVERLAY ── */}
      {successLevel && (
        <div className="modal-overlay">
          <div className="success-card">
            <img src={AVATARS.shocked} alt="" className="success-avatar" />
            <h3 style={{ fontFamily: "'Tajawal',sans-serif", fontSize: 26, fontWeight: 900, color: "#00f5c8", marginBottom: 8 }}>اختراق ناجح! 🎉</h3>
            <p style={{ fontFamily: "'Tajawal',sans-serif", fontSize: 15, color: "#b8dce8", lineHeight: 1.8, marginBottom: 18 }}>{successLevel.successMsg}</p>
            <div className="secret-box" style={{ marginBottom: 20 }}>🔑 {successLevel.targetSecret}</div>
            <div style={{ display: "flex", justifyContent: "center", gap: 24, marginBottom: 22 }}>
              {[{ n: attempts, l: "محاولات" }, { n: score, l: "نقطة" }, { n: `L${successLevel.id}`, l: "Level" }].map(s => (
                <div key={s.l} style={{ textAlign: "center" }}>
                  <div style={{ fontSize: 26, fontWeight: 700, color: "#f5c842" }}>{s.n}</div>
                  <div style={{ fontSize: 10, color: "#3a6070", textTransform: "uppercase", letterSpacing: 1 }}>{s.l}</div>
                </div>
              ))}
            </div>
            <button className="inp-submit" onClick={() => { setSuccessLevel(null); if (levelIdx < LEVELS.length - 1) setLevelIdx(l => l + 1); else setScreen("leaderboard"); }}>
              {levelIdx < LEVELS.length - 1 ? `Level ${levelIdx + 2} — استمر! ▶` : "🏆 Leaderboard"}
            </button>
          </div>
        </div>
      )}
    </>
  );
}

// ─── Live Bar ─────────────────────────────────────────
function LiveBar({ attempts, loggedAlias, onLeaderboard }) {
  return (
    <div className="live-bar">
      <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
        <div style={{ width: 6, height: 6, borderRadius: "50%", background: "#ff3a5c", animation: "blink .9s infinite" }} />
        <span style={{ color: "#3a6070", fontSize: 10, textTransform: "uppercase", letterSpacing: 1 }}>Live</span>
      </div>
      <span style={{ color: "#3a6070" }}>Total Attempts: <span style={{ color: "#00f5c8", fontWeight: 600 }}>{(1247 + attempts).toLocaleString()}</span></span>
      <span style={{ color: "#3a6070" }}>Successful Hacks: <span style={{ color: "#ff3a5c", fontWeight: 600 }}>12</span></span>
      <button className="lb-link" onClick={onLeaderboard}>🏆 Leaderboard</button>
      {loggedAlias && <span style={{ color: "#00f5c8", fontSize: 11 }}>▶ {loggedAlias}</span>}
    </div>
  );
}

// ─── Styles ───────────────────────────────────────────
const STYLES = `
@import url('https://fonts.googleapis.com/css2?family=Tajawal:wght@400;700;900&family=IBM+Plex+Mono:wght@400;600&family=Bebas+Neue&display=swap');
*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
:root{
  --bg:#060d10;--surface:#0b1a20;--card:#0e2028;--border:#112a35;
  --neon:#00f5c8;--red:#ff3a5c;--orange:#ff8c42;--gold:#f5c842;
  --muted:#3a6070;--text:#b8dce8;--white:#f0faff;
  --mono:'IBM Plex Mono',monospace;--ar:'Tajawal',sans-serif;--display:'Bebas Neue',sans-serif;
}
html,body{min-height:100vh;overflow-x:hidden}
body{background:var(--bg);color:var(--text);font-family:var(--mono);font-size:14px}
body::before{content:'';position:fixed;inset:0;background:repeating-linear-gradient(0deg,transparent,transparent 2px,rgba(0,245,200,.011) 2px,rgba(0,245,200,.011) 4px);pointer-events:none;z-index:9999}
.neon{color:var(--neon)}
@keyframes blink{0%,100%{opacity:1}50%{opacity:0}}
@keyframes float{0%,100%{transform:translateY(0)}50%{transform:translateY(-6px)}}
@keyframes slideUp{from{opacity:0;transform:translateY(16px)}to{opacity:1;transform:translateY(0)}}
@keyframes popIn{from{opacity:0;transform:scale(.85) translateY(10px)}to{opacity:1;transform:scale(1) translateY(0)}}
@keyframes bounceIn{0%{transform:scale(.55);opacity:0}60%{transform:scale(1.06)}100%{transform:scale(1);opacity:1}}
@keyframes shake{0%,100%{transform:translateX(0)}20%{transform:translateX(-7px)}40%{transform:translateX(7px)}60%{transform:translateX(-4px)}80%{transform:translateX(4px)}}
@keyframes glitch{0%,100%{clip-path:inset(0 0 100% 0)}15%{clip-path:inset(8% 0 80% 0);transform:translate(-3px,1px)}30%{clip-path:inset(55% 0 32% 0);transform:translate(3px,-1px)}50%{clip-path:inset(0 0 0 0);transform:translate(0)}}
@keyframes pulse{0%,100%{box-shadow:0 0 6px var(--neon),0 0 20px rgba(0,245,200,.2)}50%{box-shadow:0 0 14px var(--neon),0 0 50px rgba(0,245,200,.4)}}

/* ── Landing ── */
.landing{min-height:100vh;display:flex;flex-direction:column;align-items:center;justify-content:center;padding:80px 20px 60px;position:relative;overflow:hidden;text-align:center}
.grid-bg{position:absolute;inset:0;background-image:linear-gradient(rgba(0,245,200,.04) 1px,transparent 1px),linear-gradient(90deg,rgba(0,245,200,.04) 1px,transparent 1px);background-size:50px 50px;mask-image:radial-gradient(ellipse 80% 80% at 50% 50%,black 15%,transparent 100%)}
.landing-inner{position:relative;z-index:1;max-width:680px;margin:0 auto}
.landing-avatar{width:160px;height:160px;border-radius:50%;object-fit:cover;border:3px solid rgba(0,245,200,.3);animation:float 4s ease-in-out infinite;box-shadow:0 0 30px rgba(0,245,200,.15);margin-bottom:20px}
.live-badge{display:inline-block;font-size:10px;letter-spacing:3px;color:var(--neon);border:1px solid rgba(0,245,200,.3);padding:4px 14px;margin-bottom:20px;animation:slideUp .5s ease}
.landing-h1{font-family:var(--ar);font-size:clamp(36px,7vw,78px);font-weight:900;color:var(--white);line-height:1.05;margin-bottom:16px;position:relative;animation:slideUp .5s .1s ease both}
.landing-h1::before,.landing-h1::after{content:attr(data-text);position:absolute;inset:0;font-family:var(--ar);font-size:inherit;font-weight:inherit;pointer-events:none}
.landing-h1::before{color:#ff3a5c;animation:glitch 5s 1.5s infinite;left:2px}
.landing-h1::after{color:#00c4ff;animation:glitch 5s 2s infinite;left:-2px}
.landing-p{font-family:var(--ar);font-size:clamp(14px,2.2vw,17px);color:var(--muted);line-height:1.85;margin-bottom:36px;animation:slideUp .5s .2s ease both}
.cta-btn{font-family:var(--display);font-size:18px;letter-spacing:3px;padding:15px 50px;border:2px solid var(--neon);background:transparent;color:var(--neon);cursor:pointer;position:relative;overflow:hidden;transition:all .3s;animation:pulse 3s infinite}
.cta-btn::before{content:'';position:absolute;inset:0;background:var(--neon);transform:translateX(-101%);transition:.3s;z-index:-1}
.cta-btn:hover{color:var(--bg)}.cta-btn:hover::before{transform:translateX(0)}
.levels-preview{display:flex;gap:10px;justify-content:center;flex-wrap:wrap;margin-top:40px;animation:slideUp .5s .35s ease both}
.lvl-card{border:1px solid var(--border);background:var(--card);padding:12px 18px;min-width:140px;cursor:pointer;transition:all .22s;text-align:left}
.lvl-card:hover{border-color:var(--neon);background:rgba(0,245,200,.04);transform:translateY(-2px)}
.lvl-num{font-size:10px;letter-spacing:2px;color:var(--muted);margin-bottom:4px}
.lvl-title{font-family:var(--ar);font-size:14px;font-weight:700;color:var(--white)}

/* ── Game Root ── */
.game-root{display:flex;flex-direction:column;min-height:100vh}
.top-bar{position:sticky;top:0;z-index:100;display:flex;align-items:center;justify-content:space-between;padding:10px 20px;background:rgba(6,13,16,.94);backdrop-filter:blur(14px);border-bottom:1px solid var(--border);flex-wrap:wrap;gap:8px}
.top-logo{font-family:var(--display);font-size:18px;letter-spacing:3px;color:var(--neon);background:none;border:none;cursor:pointer}
.top-pills{display:flex;gap:6px;flex-wrap:wrap}
.top-pill{padding:4px 12px;font-size:10px;letter-spacing:1.5px;text-transform:uppercase;border:1px solid var(--border);background:transparent;color:var(--muted);cursor:pointer;transition:all .2s;font-family:var(--mono)}
.top-pill:hover{border-color:var(--muted);color:var(--text)}.top-pill.active{background:rgba(0,245,200,.06)}
.top-score{font-size:11px;color:var(--gold)}

/* ── Game Grid: Chat | Trace ── */
.game-grid{display:grid;grid-template-columns:1fr 300px;flex:1;gap:0;min-height:calc(100vh - 50px - 44px)}
@media(max-width:820px){.game-grid{grid-template-columns:1fr;grid-template-rows:1fr auto}}
.game-grid.shake{animation:shake .4s ease}

/* ── Chat Column ── */
.chat-col{display:flex;align-items:flex-start;justify-content:center;padding:24px 20px;border-right:1px solid var(--border);overflow-y:auto}
@media(max-width:820px){.chat-col{border-right:none;border-bottom:1px solid var(--border);padding:16px}}
.chat-card{width:100%;max-width:640px;display:flex;flex-direction:column;background:var(--card);border:1px solid var(--border);min-height:calc(100vh - 140px)}
@media(max-width:820px){.chat-card{min-height:auto}}

.persona-row{display:flex;align-items:center;gap:14px;padding:16px 18px;border-bottom:1px solid var(--border);background:linear-gradient(90deg,var(--surface),transparent)}
.persona-avatar{width:72px;height:72px;border-radius:50%;object-fit:cover;border:2px solid rgba(0,245,200,.3);animation:float 4s ease-in-out infinite;flex-shrink:0;box-shadow:0 0 16px rgba(0,245,200,.15)}
.persona-name{font-family:var(--ar);font-size:15px;font-weight:700;color:var(--white)}
.persona-desc{font-size:10px;color:var(--muted);margin-top:2px}
.persona-target{margin-top:6px;display:flex;align-items:center;gap:6px;flex-wrap:wrap}

.messages-area{flex:1;overflow-y:auto;padding:16px;display:flex;flex-direction:column;gap:12px;scroll-behavior:smooth;min-height:300px;max-height:calc(100vh - 340px)}
@media(max-width:820px){.messages-area{max-height:300px}}
.messages-area::-webkit-scrollbar{width:3px}.messages-area::-webkit-scrollbar-thumb{background:var(--border)}

.msg-row{display:flex;gap:9px;align-items:flex-start;animation:popIn .28s ease}
.msg-user{flex-direction:row-reverse}
.msg-avi{width:34px;height:34px;border-radius:50%;overflow:hidden;flex-shrink:0;border:1px solid var(--border)}
.msg-avi img{width:100%;height:100%;object-fit:cover}
.user-avi{background:rgba(0,245,200,.08);border-color:var(--neon);display:flex;align-items:center;justify-content:center;font-size:14px}
.bubble{max-width:78%;padding:10px 14px;font-family:var(--ar);font-size:15px;line-height:1.65;direction:rtl;text-align:right;border:1px solid var(--border)}
.bub-bot{background:var(--surface);border-color:var(--border)}
.bub-user{background:rgba(0,245,200,.05);border-color:rgba(0,245,200,.18)}
.bub-blocked{background:rgba(255,58,92,.06);border-color:var(--red);color:var(--red)}
.bub-success{background:rgba(0,245,200,.06);border-color:var(--neon);color:var(--neon)}
.bub-warn{background:rgba(255,140,66,.05);border-color:var(--orange);color:var(--orange)}
.msg-badge{display:inline-flex;align-items:center;gap:5px;font-size:9px;letter-spacing:1.5px;text-transform:uppercase;padding:2px 8px;border:1px solid;margin-bottom:5px}
.badge-red{border-color:var(--red);color:var(--red);background:rgba(255,58,92,.1)}
.badge-green{border-color:var(--neon);color:var(--neon);background:rgba(0,245,200,.08)}
.secret-box{font-family:var(--mono);background:rgba(0,245,200,.1);border:1px solid var(--neon);padding:6px 11px;font-size:11px;direction:ltr;text-align:left;margin-top:7px;word-break:break-all;color:var(--neon)}
.typing-dots{display:flex;gap:4px;padding:12px 14px;background:var(--card);border:1px solid var(--border)}
.typing-dots span{width:6px;height:6px;border-radius:50%;background:var(--muted);animation:blink 1.2s infinite}
.typing-dots span:nth-child(2){animation-delay:.2s}.typing-dots span:nth-child(3){animation-delay:.4s}

.input-area{padding:12px 16px;border-top:1px solid var(--border);background:var(--surface)}
.input-row{display:flex;gap:7px}
.term-input{flex:1;background:rgba(0,0,0,.5);border:1px solid var(--border);color:var(--neon);font-family:var(--mono);font-size:13px;padding:10px 12px;outline:none;resize:none;caret-color:var(--neon);transition:border-color .2s;min-height:44px;max-height:110px}
.term-input::placeholder{color:rgba(0,245,200,.18)}.term-input:focus{border-color:var(--neon)}.term-input:disabled{opacity:.4}
.exec-btn{padding:10px 16px;background:var(--neon);border:none;color:var(--bg);font-family:var(--mono);font-size:12px;letter-spacing:1px;cursor:pointer;font-weight:700;text-transform:uppercase;transition:all .2s;white-space:nowrap}
.exec-btn:hover{background:#00c4ff}.exec-btn:disabled{opacity:.4;cursor:not-allowed}
.input-hint{font-size:10px;color:var(--muted);margin-top:5px;letter-spacing:.4px}

/* ── Trace Column ── */
.trace-col{display:flex;flex-direction:column;background:var(--surface);height:calc(100vh - 94px);position:sticky;top:50px;overflow-y:auto}
@media(max-width:820px){.trace-col{height:auto;position:static;max-height:380px}}
.trace-col::-webkit-scrollbar{width:3px}.trace-col::-webkit-scrollbar-thumb{background:var(--border)}
.trace-card{display:flex;flex-direction:column;flex:1;padding:14px}
.trace-title{display:flex;align-items:center;gap:8px;font-size:10px;letter-spacing:2px;text-transform:uppercase;color:var(--text);margin-bottom:3px}
.trace-dot{width:7px;height:7px;border-radius:50%;background:var(--neon);animation:blink 1.4s infinite}
.trace-subtitle{font-size:9px;color:var(--muted);letter-spacing:1px;margin-bottom:14px;border-bottom:1px solid var(--border);padding-bottom:10px}
.trace-empty{flex:1;display:flex;flex-direction:column;align-items:center;justify-content:center;padding:30px 16px}
.trace-content{display:flex;flex-direction:column;gap:8px}
.trace-phase{border:1px solid var(--border);overflow:hidden}
.phase-green{border-color:rgba(0,245,200,.2)}.phase-red{border-color:var(--red)}.phase-orange{border-color:var(--orange)}.phase-skip{opacity:.4}
.phase-toggle{width:100%;display:flex;align-items:center;justify-content:space-between;padding:8px 11px;background:rgba(0,0,0,.2);cursor:pointer;border:none;color:var(--text);font-family:var(--mono);font-size:10px;letter-spacing:1.2px;text-transform:uppercase;gap:6px}
.phase-badge{font-size:9px;letter-spacing:1px;text-transform:uppercase;padding:2px 7px;border:1px solid;flex-shrink:0}
.badge-green{border-color:var(--neon);color:var(--neon);background:rgba(0,245,200,.07)}
.badge-red{border-color:var(--red);color:var(--red);background:rgba(255,58,92,.07)}
.badge-orange{border-color:var(--orange);color:var(--orange);background:rgba(255,140,66,.07)}
.badge-skip{border-color:var(--muted);color:var(--muted)}
.phase-body{padding:8px 11px;display:flex;flex-direction:column;gap:4px;border-top:1px solid var(--border)}

/* ── Live Bar ── */
.live-bar{position:fixed;bottom:0;left:0;right:0;z-index:100;padding:8px 22px;background:rgba(6,13,16,.95);border-top:1px solid var(--border);display:flex;align-items:center;justify-content:center;gap:24px;font-size:11px;flex-wrap:wrap}
.lb-link{background:none;border:none;color:var(--gold);cursor:pointer;font-family:var(--mono);font-size:11px;letter-spacing:1px}
.lb-link:hover{color:var(--white)}

/* ── Leaderboard ── */
.lb-page{min-height:100vh;padding:80px 20px 80px}
.lb-inner{max-width:820px;margin:0 auto}
.lb-h{font-family:var(--ar);font-size:clamp(24px,5vw,48px);font-weight:900;color:var(--white);margin-bottom:6px;text-align:center}
.lb-sub{font-size:10px;color:var(--muted);letter-spacing:3px;text-transform:uppercase;text-align:center;margin-bottom:36px}
.lb-table{width:100%;border-collapse:collapse}
.lb-table th{padding:11px 16px;text-align:left;font-size:9px;letter-spacing:2px;text-transform:uppercase;color:var(--muted);border-bottom:1px solid var(--border)}
.lb-table td{padding:13px 16px;border-bottom:1px solid rgba(17,42,53,.5);transition:background .2s}
.lb-table tr:hover td{background:rgba(0,245,200,.02)}
.rank-1{color:var(--gold);font-weight:700;font-size:15px}.rank-2{color:#c0c0c0;font-weight:700}.rank-3{color:#cd7f32;font-weight:700}
.hacked-badge{display:inline-flex;align-items:center;gap:4px;font-size:10px;padding:3px 10px;border:1px solid rgba(0,245,200,.3);background:rgba(0,245,200,.05);color:var(--neon)}
.back-btn{display:flex;align-items:center;gap:6px;background:none;border:none;color:var(--muted);cursor:pointer;font-family:var(--mono);font-size:11px;letter-spacing:1px;text-transform:uppercase;margin-bottom:24px;padding:0;transition:color .2s}
.back-btn:hover{color:var(--neon)}

/* ── Modal ── */
.modal-overlay{position:fixed;inset:0;z-index:300;background:rgba(6,13,16,.9);backdrop-filter:blur(12px);display:flex;align-items:center;justify-content:center;padding:20px}
.modal-box{background:var(--surface);border:1px solid var(--neon);width:100%;max-width:420px;padding:34px;position:relative;box-shadow:0 0 60px rgba(0,245,200,.12);animation:bounceIn .3s ease}
.modal-close{position:absolute;top:13px;right:13px;background:none;border:none;color:var(--muted);cursor:pointer;font-size:17px;transition:color .2s}
.modal-close:hover{color:var(--red)}
.inp-lbl{display:block;font-size:10px;letter-spacing:2px;text-transform:uppercase;color:var(--neon);margin-bottom:7px}
.inp-field{width:100%;background:rgba(0,0,0,.4);border:1px solid var(--border);color:var(--text);font-family:var(--mono);font-size:13px;padding:11px 13px;outline:none;transition:all .2s;margin-bottom:16px}
.inp-field:focus{border-color:var(--neon)}.inp-field::placeholder{color:var(--muted)}
.inp-submit{width:100%;padding:12px;font-size:13px;letter-spacing:2px;background:var(--neon);border:none;color:var(--bg);font-family:var(--mono);cursor:pointer;font-weight:700;text-transform:uppercase;transition:all .2s;margin-top:4px}
.inp-submit:hover{background:#00c4ff}.inp-submit:disabled{opacity:.4;cursor:not-allowed}
.social-btn{flex:1;padding:9px;background:transparent;border:1px solid var(--border);color:var(--text);font-family:var(--mono);font-size:11px;cursor:pointer;display:flex;align-items:center;justify-content:center;gap:6px;transition:all .2s;letter-spacing:1px}
.social-btn:hover{border-color:var(--neon);color:var(--neon)}

/* ── Success ── */
.success-card{background:var(--surface);border:2px solid var(--neon);width:100%;max-width:440px;padding:34px;text-align:center;box-shadow:0 0 70px rgba(0,245,200,.18);animation:bounceIn .4s ease;position:relative}
.success-avatar{width:110px;height:110px;border-radius:50%;object-fit:cover;border:3px solid var(--neon);margin:0 auto 14px;display:block;animation:float 3s ease-in-out infinite;box-shadow:0 0 30px rgba(0,245,200,.25)}

/* ── Flash ── */
.flash{position:fixed;top:62px;left:50%;transform:translateX(-50%);z-index:500;padding:9px 24px;font-family:var(--ar);font-size:14px;font-weight:700;border:1px solid;animation:popIn .3s ease;pointer-events:none;white-space:nowrap}
.flash.plus{background:rgba(0,245,200,.1);border-color:var(--neon);color:var(--neon)}
.flash.minus{background:rgba(255,58,92,.1);border-color:var(--red);color:var(--red)}

@media(max-width:500px){
  .top-bar{padding:8px 12px}.live-bar{gap:10px;font-size:10px}
  .persona-row{padding:12px}.persona-avatar{width:56px;height:56px}
  .messages-area{padding:10px}.input-area{padding:10px 12px}
}
`;